#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define MAX_NODES 500
#define MAX_K 100
// Define the structure for a tree node
typedef struct TreeNode {
    int val;
    struct TreeNode *left;
    struct TreeNode *right;
} TreeNode;
// Function to create a new tree node
TreeNode* createTreeNode(int val) {
    TreeNode* node = (TreeNode*) malloc(sizeof(TreeNode));
    node->val = val;
    node->left = NULL;
    node->right = NULL;
    return node;
}
// Function to find the target node in the tree
TreeNode* findTargetNode(TreeNode* root, int target) {
    if (root == NULL) return NULL;
    if (root->val == target) return root;
    TreeNode* left = findTargetNode(root->left, target);
    if (left != NULL) return left;
    return findTargetNode(root->right, target);
}
// Function to perform BFS to find nodes at distance k
void bfs(TreeNode* root, int k, int* result, int* count) {
    if (root == NULL || k < 0) return;
    if (k == 0) {
        result[(*count)++] = root->val;
        return;
    }
    bfs(root->left, k - 1, result, count);
    bfs(root->right, k - 1, result, count);
}
// Function to solve the problem
void solve(int numNodes, int target, int k, int* treeValues) {
    // Create the tree
    TreeNode* root = NULL;
    TreeNode** nodes = (TreeNode**) malloc(numNodes * sizeof(TreeNode*));
    for (int i = 0; i < numNodes; i++) {
        if (treeValues[i] != -1) {
            nodes[i] = createTreeNode(treeValues[i]);
        } else {
            nodes[i] = NULL;
        }
    }
    for (int i = 0; i < numNodes; i++) {
        if (nodes[i] != NULL) {
            if (2 * i + 1 < numNodes && nodes[2 * i + 1] != NULL) {
                nodes[i]->left = nodes[2 * i + 1];
            }
            if (2 * i + 2 < numNodes && nodes[2 * i + 2] != NULL) {
                nodes[i]->right = nodes[2 * i + 2];
            }
        }
    }
    root = nodes[0];
    // Find the target node
    TreeNode* targetNode = findTargetNode(root, target);
    if (targetNode == NULL) return;
    // Perform BFS to find nodes at distance k
    int result[MAX_NODES];
    int count = 0;
    bfs(targetNode, k, result, &count);
    // Print the result
    for (int i = 0; i < count; i++) {
        printf("%d ", result[i]);
    }
    printf("\n");
}
int main() {
    int T;
    scanf("%d", &T);
    for (int t = 0; t < T; t++) {
        int numNodes, target, k;
        scanf("%d %d %d", &numNodes, &target, &k);
        int treeValues[numNodes];
        for (int i = 0; i < numNodes; i++) {
            scanf("%d", &treeValues[i]);
        }
        solve(numNodes, target, k, treeValues);
    }
    return 0;
}

